B.afC=new A.T("Eine rechteckige Leiterschleife der H\xf6he b wird durch ein homogenes Magnetfeld B (in die Zeichenebene hinein) bewegt. \xc4ndert sich dabei der magnetische Fluss durch die Schleife, so wird eine Spannung induziert.",null,B.og,null,null,null,null,null,null,null)
B.dz=new A.dD(null,16,null,null)
B.fM=new A.q(!0,null,null,null,null,null,16,B.N,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.tE=new A.T("Magnetischer Fluss",null,B.fM,null,null,null,null,null,null,null)
B.dN=new A.q(!0,null,null,null,null,null,13,null,null,null,null,null,1.5,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.aen=new A.T("Der Fluss ist das Produkt aus Flussdichte und der vom Feld durchsetzten Fl\xe4che A der Schleife:\n\n  \u03a6 = B \xb7 A\n\nSolange sich die linke Leiterstange im Feld befindet, ist A = (10 cm \u2212 x) \xb7 b. Schiebt man die Schleife heraus, nimmt A und damit \u03a6 ab.",null,B.dN,null,null,null,null,null,null,null)
B.tF=new A.T("Induktionsgesetz",null,B.fM,null,null,null,null,null,null,null)
B.adg=new A.T("Nach dem Faradayschen Induktionsgesetz ist die induzierte Spannung gleich der negativen zeitlichen \xc4nderung des Flusses:\n\n  U\u1d62 = \u2212d\u03a6/dt\n\nBei der waagerechten Bewegung der Leiterstange mit der Geschwindigkeit v ergibt sich daraus\n\n  U\u1d62 = B \xb7 b \xb7 v.",null,B.dN,null,null,null,null,null,null,null)
B.aeq=new A.T("Bewegung l\xe4ngs und quer",null,B.fM,null,null,null,null,null,null,null)
B.ach=new A.T("Nur die waagerechte Bewegung ver\xe4ndert die im Feld liegende Fl\xe4che und erzeugt eine Spannung. Verschiebt man die vollst\xe4ndig im Feld liegende Schleife senkrecht, bleibt der Fluss konstant \u2013 es wird keine Spannung induziert.",null,B.dN,null,null,null,null,null,null,null)
