B.aeE=new A.T("Generator",null,B.oi,null,null,null,null,null,null,null)
B.acr=new A.T("Eine flache Spule mit N Windungen rotiert mit der Periodendauer T in einem homogenen Magnetfeld der Flussdichte B. Durch die Drehung \xe4ndert sich die vom Feld senkrecht durchsetzte Fl\xe4che der Spule st\xe4ndig \u2013 und damit der magnetische Fluss. Nach dem Induktionsgesetz entsteht so eine Wechselspannung.",null,B.og,null,null,null,null,null,null,null)
B.aeQ=new A.T("Steht die Spulenebene senkrecht zum Feld, ist der Fluss maximal; liegt sie parallel zum Feld, verschwindet er. Mit dem Drehwinkel \u03b8 = \u03c9\xb7t gilt:\n\n  \u03a6(t) = B \xb7 A \xb7 cos(\u03c9\xb7t)\n\nA ist die Spulenfl\xe4che und \u03c9 = 2\u03c0/T die Winkelgeschwindigkeit.",null,B.dN,null,null,null,null,null,null,null)
B.adS=new A.T("Die induzierte Spannung ist das Negative der zeitlichen \xc4nderung des Flusses, multipliziert mit der Windungszahl:\n\n  U\u1d62(t) = \u2212N \xb7 d\u03a6/dt = N \xb7 B \xb7 A \xb7 \u03c9 \xb7 sin(\u03c9\xb7t)\n\nEs entsteht eine sinusf\xf6rmige Wechselspannung mit dem Scheitelwert\n\n  \xdb = N \xb7 B \xb7 A \xb7 \u03c9.\n\nSpannung und Fluss sind um eine Viertelperiode phasen-verschoben: Ist der Fluss maximal, so ist seine \xc4nderungsrate und damit die Spannung null \u2013 und umgekehrt.",null,B.dN,null,null,null,null,null,null,null)
B.ae2=new A.T("Lorentzkraft und Geschwindigkeit",null,B.fM,null,null,null,null,null,null,null)
B.aeO=new A.T("Auf die bewegten Ladungen in den Leiterst\xe4ben wirkt die Lorentzkraft. Nur die Geschwindigkeitskomponente senkrecht zum Magnetfeld tr\xe4gt zur Induktion bei. Sie ist beim Durchgang durch die Feldrichtung am gr\xf6\xdften \u2013 genau dann ist auch die Induktionsspannung maximal.",null,B.dN,null,null,null,null,null,null,null)
